## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
$b = random(4, 7);
$m = list_random(
  Fraction(3, 4), Fraction(3, 5), Fraction(4, 5), Fraction(5, 6), Fraction(4, 7),
  Fraction(5, 7), Fraction(6, 7), Fraction(5, 8), Fraction(7, 8)
);
$d = ($m->value)[1];
$n = random(2*$d, 25, $d);
$total = $b + $m*$n;
Context()->variables->are(n => 'Real');
$proposed_solution = (random(0,1)) ? $n : $n + non_zero_random(-3, 3);
$left = Formula("$b + $m n");
$right = Formula("$total");
$lefteval = Real($left->eval(n => $proposed_solution));
$righteval = Real($right->eval(n => $proposed_solution));
Context("LimitedNumeric");
$lefteval = Real($lefteval);
$righteval = Real($righteval);
$dropdown = DropDown(
  ["Yes, it is a solution.", "No, it is not a solution."],
  ($lefteval == $righteval) ? 0 : 1, showInStatic => 0
);

############################################################
# Body
############################################################

BEGIN_PGML
When a young tree was planted in your school's garden, it was [$b] feet tall. It grows [$m] feet per year. After some number [`n`] of years, the tree is [$total] feet tall. This gives us the equation [`[$left]=[$right]\text{.}`] Has it been [`[$proposed_solution]`] years?

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`=`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{=}`]'),
     PGML('[`[$righteval->TeX]`]'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
